-- Farming Operations (High-Impact) - Assess (variant 149)
UPDATE product_content SET
  description = 'Understand where your farming operations fall short on yield visibility, resource efficiency, and planning accuracy. The DigitalQatalyst team assesses your current operational maturity and returns a prioritised roadmap your agribusiness leaders can act on.',
  positioning = 'A structured assessment that reveals where operational gaps are costing yield, water, and labour, and what to fix first.',
  hero_summary = 'Understand where your farming operations fall short on yield visibility, resource efficiency, and planning accuracy. The DigitalQatalyst team assesses your current operational maturity and returns a prioritised roadmap your agribusiness leaders can act on.',
  overview_paragraphs = '["The Farming Operations Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps operational maturity and returns prioritised improvements your operations leaders can act on.","See how farming operations perform today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for agribusiness & farm operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews farming operations across business operations and productivity.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Fixed-scope assessment delivered within one week","Covers crop, livestock, and mixed farming operation models","No obligation to proceed with subsequent design or deployment"]'::jsonb,
  why_it_matters = '{"hook":"Farming operations depend on timely data, coordinated field activity, and resilient supply chain execution.","problemParagraph":"Many agribusinesses run farming operations with manual field coordination, inconsistent yield data, and limited visibility into supply chain risk. This assessment maps operational maturity and returns prioritised improvements your operations leaders can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Fragmented operations data","description":"Agricultural operations teams work from disconnected systems without a single operational view."},{"title":"Inconsistent field processes","description":"Standard operating procedures vary by site, team, or shift."},{"title":"Limited digitisation baseline","description":"Automation and analytics opportunities are unclear and unprioritised."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Operational priority map","description":"You know which agricultural operations processes and systems to improve first."},{"title":"Ranked improvement backlog","description":"Gaps are ordered for design, technology, and investment."},{"title":"Leadership-ready roadmap","description":"Recommendations support governance review and transformation funding."}]}}'::jsonb,
  faq_intro = 'Key questions about the farming operations assessment.'
WHERE variant_id = 149;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (149, 'Farming operations maturity scorecard', 'Ratings across yield tracking, resource management, planning accuracy, and equipment utilisation, with evidence and specific gaps.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (149, 'Operational gap register', 'Documented gaps in crop monitoring, irrigation scheduling, input management, and harvest coordination, ranked by cost and yield impact.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (149, 'Prioritised improvement roadmap', 'Sequenced actions with owners, effort estimates, and dependencies your operations team can act on from the first season.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (149, 'Leadership briefing pack', 'A concise summary of findings and recommended investment for agribusiness and farm operations leadership.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (149, 'What farming models does the assessment cover?', 'Broadacre cropping, horticulture, livestock, and mixed operations. The DigitalQatalyst team confirms the applicable model during scoping.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (149, 'Do you need access to our farm management systems?', 'We review system outputs and operational records rather than live data. Any access required is read-only and agreed in advance.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (149, 'What do we get at the end?', 'A maturity scorecard, an operational gap register, a prioritised improvement roadmap, and a leadership briefing pack.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (149, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm the farming operation type, geographic scope, and key stakeholders before work begins.', 3);

-- Farming Operations (High-Impact) - Design (variant 150)
UPDATE product_content SET
  description = 'Turn farming operations improvement goals into a complete, build-ready blueprint: field monitoring workflows, resource scheduling logic, integration specifications, and an adoption plan your operations team can execute from the next season.',
  positioning = 'A design engagement that produces farming operations specifications ready for technology configuration and rollout.',
  hero_summary = 'Turn farming operations improvement goals into a complete, build-ready blueprint: field monitoring workflows, resource scheduling logic, integration specifications, and an adoption plan your operations team can execute from the next season.',
  overview_paragraphs = '["The Farming Operations Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement defines farming operations and build-ready specifications.","Turn farming operations goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for agribusiness & farm operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate farming operations requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Design-only engagement: no platform commitment required","Rollout phasing aligned to your seasonal operating calendar","Blueprint covers IoT, field management, and logistics integrations"]'::jsonb,
  why_it_matters = '{"hook":"Farming operations depend on timely data, coordinated field activity, and resilient supply chain execution.","problemParagraph":"Many farming organisations digitise operations without designed field workflows, asset models, or specifications teams can deploy across sites. This design engagement defines farming operations and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined operational workflows","description":"Agricultural operations journeys from intake to completion are not designed end to end."},{"title":"Integration gaps","description":"Field, ERP, and customer systems lack clear data and event contracts."},{"title":"Rollout ambiguity","description":"Teams lack specs to pilot and scale changes across sites."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Aligned operational designs","description":"Workflows reflect how agricultural operations teams actually deliver service."},{"title":"Consistent standards","description":"Data, integration, and governance requirements are defined upfront."},{"title":"Implementation-ready specs","description":"Delivery teams receive artefacts they can execute across locations."}]}}'::jsonb,
  faq_intro = 'Key questions about the farming operations design engagement.'
WHERE variant_id = 150;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (150, 'Field operations workflow maps', 'End-to-end flows covering crop monitoring, resource scheduling, exception handling, and harvest coordination across all relevant roles.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (150, 'Resource scheduling specification', 'Irrigation, input application, and equipment allocation rules documented for configuration or development teams.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (150, 'Integration design', 'Data flows and API patterns for farm management systems, sensor networks, weather data providers, and logistics platforms.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (150, 'Seasonal adoption plan', 'Phased rollout timed to your crop calendar, with training requirements by role and success metrics to track uptake.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (150, 'Does the design work with our existing farm management system?', 'Yes. The DigitalQatalyst team designs around your current platform, documenting configuration changes and integration updates needed to close operational gaps.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (150, 'How are field operators involved in the design?', 'Field supervisors and operators are included in workflow workshops to ensure monitoring and scheduling flows work in practice, not just on paper.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (150, 'How do we get started?', 'Contact the DigitalQatalyst team to confirm the farming operation model, the systems in scope, and the seasonal timeline constraints before the engagement begins.', 2);

-- Farming Operations (High-Impact) - AI Design (variant 151)
UPDATE product_content SET
  description = 'Validate where AI can improve yield prediction, irrigation scheduling, and pest or disease detection before any build investment is committed. The DigitalQatalyst team designs responsible, audit-ready workflows and deployment-ready specifications for every approved agricultural AI use case.',
  positioning = 'Define the AI use cases that will improve yield and reduce input waste, with data readiness and responsible workflow design confirmed before build.',
  hero_summary = 'Validate where AI can improve yield prediction, irrigation scheduling, and pest or disease detection before any build investment is committed. The DigitalQatalyst team designs responsible, audit-ready workflows and deployment-ready specifications for every approved agricultural AI use case.',
  overview_paragraphs = '["The Farming Operations AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for farming operations, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for agribusiness & farm operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for farming operations.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Validates feasibility before any AI build investment is committed","Covers yield, irrigation, pest, and crop health AI use cases","Responsible by design: agronomist review gates at every decision point"]'::jsonb,
  why_it_matters = '{"hook":"Farming operations depend on timely data, coordinated field activity, and resilient supply chain execution.","problemParagraph":"Many organisations apply AI to your farming operations without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for farming operations lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for farming operations are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Key questions about the farming operations AI design engagement.'
WHERE variant_id = 151;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (151, 'Agricultural AI use-case feasibility register', 'Each candidate scored on data availability, model complexity, and expected yield or cost improvement, with a clear go or no-go recommendation.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (151, 'Farm data readiness report', 'Gaps in sensor coverage, imagery resolution, historical data depth, and integration availability that must be addressed before model development.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (151, 'Responsible farming AI workflows', 'Designed flows for approved use cases with agronomist review points, confidence display for field operators, and documented override procedures.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (151, 'Deployment and monitoring specification', 'Model selection guidance, performance thresholds, seasonal retraining triggers, and field-level monitoring requirements for production use.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (151, 'Which AI use cases are most commonly explored?', 'Yield forecasting by field and variety, variable-rate irrigation scheduling, early pest and disease detection from imagery, and harvest timing optimisation.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (151, 'What if our sensor and imagery coverage is incomplete?', 'The data readiness report identifies specific gaps. Many operations start with yield forecasting using historical records while sensor networks are expanded in parallel.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (151, 'How do agronomists interact with AI recommendations?', 'Agronomist review gates are designed into every workflow with confidence displays and one-click override capability so field expertise always has the final say.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (151, 'How do we get started?', 'Book a consultation with the DigitalQatalyst team to identify your highest-value AI use cases and share your current data landscape and sensor coverage.', 3);

-- Farming Operations (High-Impact) - Deploy (variant 152)
