INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (152, 'Configured farming operations platform', 'Production-ready crop monitoring, resource scheduling, and logistics coordination capability tested against approved specifications.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (152, 'Integration test evidence pack', 'Test cases, results, and defect closure evidence for every connected system including farm management software, IoT networks, and logistics platforms.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (152, 'Field acceptance sign-off', 'Documented UAT results from farm managers and field operators confirming the platform meets operational requirements across all relevant workflows.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (152, 'Operational handover kit', 'Administrator guides, seasonal configuration checklist, support escalation paths, and a 30-day post-launch review schedule.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (152, 'How do you handle seasonal timing constraints for go-live?', 'The deployment plan maps milestones to your crop calendar. The DigitalQatalyst team avoids scheduling critical testing or go-live activities during planting or harvest peaks.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (152, 'What happens if sensor data quality issues are found during integration testing?', 'Data quality issues are documented, triaged, and resolved within the deployment scope where possible. Issues requiring infrastructure changes are escalated to the project sponsor.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (152, 'How are field operators trained on the new platform?', 'Role-specific training is included in the deployment plan, with field-accessible guides and refresher support available during the hypercare period.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (152, 'How do we get started?', 'Contact the DigitalQatalyst team to confirm the platform, integration scope, and seasonal calendar constraints before deployment planning begins.', 3);

