INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (154, 'Monthly farming operations report', 'Yield tracking accuracy, resource consumption versus plan, equipment utilisation, and system health metrics with commentary and recommended actions.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (154, 'Incident and change log', 'Transparent record of system incidents, configuration changes, and SLA performance for each reporting period.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (154, 'Seasonal configuration update', 'Platform updates reflecting new crop programmes, field boundary changes, or equipment additions before each new season begins.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (154, 'Annual operations roadmap', 'Forward-looking plan covering platform capability additions, data quality improvements, and structural changes aligned to the farming business plan.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (154, 'What is covered under the managed service?', 'Platform monitoring, incident response, seasonal configuration updates, monthly reporting, and annual optimisation reviews. Full scope is confirmed in the service agreement.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (154, 'How are configuration updates timed around the crop calendar?', 'The DigitalQatalyst team schedules all configuration changes outside critical planting and harvest windows, confirmed with operations leads at the start of each season.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (154, 'Can the service scale as we add new farms or crops?', 'Yes. Additional farms, fields, or crop programmes are onboarded under the service. Large structural changes are scoped and priced separately.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (154, 'How do we get started?', 'Contact the DigitalQatalyst team to confirm the platform in scope, the current configuration baseline, and the seasonal calendar before the service agreement is drafted.', 3);

-- Manufacturing Operations (High-Impact) - Assess (variant 155)
UPDATE product_content SET
  description = 'Identify where your manufacturing operations are losing throughput, masking quality issues, or running blind on downtime. The DigitalQatalyst team assesses plant operational maturity and delivers a prioritised roadmap your operations and plant leaders can act on.',
  positioning = 'A structured plant assessment that shows where production gaps are costing throughput and quality, and what to address first.',
  hero_summary = 'Identify where your manufacturing operations are losing throughput, masking quality issues, or running blind on downtime. The DigitalQatalyst team assesses plant operational maturity and delivers a prioritised roadmap your operations and plant leaders can act on.',
  overview_paragraphs = '["The Manufacturing Operations Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps operational maturity and returns prioritised improvements your plant and operations leaders can act on.","See how manufacturing operations perform today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for manufacturing & plant operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews manufacturing operations across business operations and productivity.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Fixed-scope assessment delivered within one week","Covers production, quality, and maintenance dimensions","No obligation to proceed with subsequent design or deployment"]'::jsonb,
  why_it_matters = '{"hook":"Manufacturing performance depends on synchronised production, quality control, and supply coordination.","problemParagraph":"Many manufacturers run plants with siloed MES, ERP, and quality data and inconsistent production workflows. This assessment maps operational maturity and returns prioritised improvements your plant and operations leaders can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Fragmented operations data","description":"Manufacturing operations teams work from disconnected systems without a single operational view."},{"title":"Inconsistent field processes","description":"Standard operating procedures vary by site, team, or shift."},{"title":"Limited digitisation baseline","description":"Automation and analytics opportunities are unclear and unprioritised."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Operational priority map","description":"You know which manufacturing operations processes and systems to improve first."},{"title":"Ranked improvement backlog","description":"Gaps are ordered for design, technology, and investment."},{"title":"Leadership-ready roadmap","description":"Recommendations support governance review and transformation funding."}]}}'::jsonb,
  faq_intro = 'Key questions about the manufacturing operations assessment.'
WHERE variant_id = 155;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (155, 'Manufacturing maturity scorecard', 'Ratings across throughput management, quality control, downtime visibility, and production coordination, with evidence and specific gaps.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (155, 'OEE and downtime gap report', 'Analysis of availability, performance, and quality losses across lines and shifts, with root-cause identification for the highest-impact losses.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (155, 'Prioritised improvement roadmap', 'Sequenced actions with owners, effort estimates, and dependencies your plant team can execute within normal production schedules.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (155, 'Leadership briefing pack', 'A concise summary of findings and recommended investment for plant, operations, and finance leadership.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (155, 'What types of manufacturing environments does the assessment cover?', 'Discrete, process, and mixed manufacturing. The DigitalQatalyst team confirms the applicable production model and equipment categories during scoping.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (155, 'Do you need to access our MES or ERP systems?', 'We review system-generated reports and operational records rather than live production systems. Any access required is read-only and agreed in advance.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (155, 'What do we get at the end?', 'A manufacturing maturity scorecard, an OEE and downtime gap report, a prioritised improvement roadmap, and a leadership briefing pack.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (155, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm the plant scope, production environment type, and key stakeholders before work begins.', 3);

-- Manufacturing Operations (High-Impact) - Design (variant 156)
UPDATE product_content SET
  description = 'Turn manufacturing improvement goals into a complete, build-ready operations blueprint: production workflow designs, quality control specifications, maintenance scheduling logic, and an adoption plan your plant teams can execute without ambiguity.',
  positioning = 'A design engagement that produces manufacturing operations specifications ready for MES configuration and plant rollout.',
  hero_summary = 'Turn manufacturing improvement goals into a complete, build-ready operations blueprint: production workflow designs, quality control specifications, maintenance scheduling logic, and an adoption plan your plant teams can execute without ambiguity.',
  overview_paragraphs = '["The Manufacturing Operations Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement defines manufacturing operations and build-ready specifications.","Turn manufacturing operations goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for manufacturing & plant operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate manufacturing operations requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Design-only engagement: no MES or ERP commitment required","Covers production, quality, and maintenance workflow dimensions","Rollout sequencing planned around your production calendar"]'::jsonb,
  why_it_matters = '{"hook":"Manufacturing performance depends on synchronised production, quality control, and supply coordination.","problemParagraph":"Many factories modernise production without designed line workflows, quality models, or specifications engineering teams can deploy. This design engagement defines manufacturing operations and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined operational workflows","description":"Manufacturing operations journeys from intake to completion are not designed end to end."},{"title":"Integration gaps","description":"Field, ERP, and customer systems lack clear data and event contracts."},{"title":"Rollout ambiguity","description":"Teams lack specs to pilot and scale changes across sites."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Aligned operational designs","description":"Workflows reflect how manufacturing operations teams actually deliver service."},{"title":"Consistent standards","description":"Data, integration, and governance requirements are defined upfront."},{"title":"Implementation-ready specs","description":"Delivery teams receive artefacts they can execute across locations."}]}}'::jsonb,
  faq_intro = 'Key questions about the manufacturing operations design engagement.'
WHERE variant_id = 156;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (156, 'Production workflow maps', 'End-to-end flows for scheduling, WIP tracking, shift handover, and exception management across all in-scope lines and work centres.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (156, 'Quality control specification', 'Inspection point definitions, defect classification rules, and corrective action escalation flows documented for configuration teams.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (156, 'Maintenance scheduling specification', 'Preventive and condition-based maintenance rules by equipment class, with production calendar integration logic.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (156, 'Plant adoption plan', 'Line-by-line rollout sequence, operator training requirements, and success metrics to track uptake without disrupting production targets.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (156, 'Does the design tie us to a specific MES platform?', 'No. The DigitalQatalyst team designs to your requirements first. Platform selection is informed by the design and your existing ERP landscape.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (156, 'How are operators involved in the design process?', 'Line operators and shift supervisors participate in workflow workshops to ensure designs reflect actual production conditions, not just management expectations.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (156, 'How do we get started?', 'Contact the DigitalQatalyst team to confirm the lines in scope, the MES and ERP platforms in use, and any production calendar constraints before the engagement begins.', 2);

-- Manufacturing Operations (High-Impact) - AI Design (variant 157)
UPDATE product_content SET
  description = 'Validate which AI use cases will genuinely improve throughput, quality, and maintenance performance before committing build budget. The DigitalQatalyst team designs responsible, audit-ready workflows and deployment-ready specifications for every approved manufacturing AI application.',
  positioning = 'Define and validate the AI use cases that will improve production output and reduce quality escapes, with data readiness confirmed before build.',
  hero_summary = 'Validate which AI use cases will genuinely improve throughput, quality, and maintenance performance before committing build budget. The DigitalQatalyst team designs responsible, audit-ready workflows and deployment-ready specifications for every approved manufacturing AI application.',
  overview_paragraphs = '["The Manufacturing Operations AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for manufacturing operations, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for manufacturing & plant operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for manufacturing operations.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Validates feasibility before any AI build investment is committed","Covers predictive maintenance, visual inspection, and scheduling AI","Responsible by design: engineer review gates at every decision point"]'::jsonb,
  why_it_matters = '{"hook":"Manufacturing performance depends on synchronised production, quality control, and supply coordination.","problemParagraph":"Many organisations apply AI to your manufacturing operations without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for manufacturing operations lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for manufacturing operations are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Key questions about the manufacturing operations AI design engagement.'
WHERE variant_id = 157;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (157, 'Manufacturing AI use-case feasibility register', 'Each candidate scored on sensor data availability, model complexity, and expected OEE or quality improvement, with a clear go or no-go recommendation.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (157, 'Plant data readiness report', 'Gaps in sensor coverage, data labelling, MES integration, and historical quality records that must be resolved before model development.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (157, 'Responsible manufacturing AI workflows', 'Designed flows for approved use cases with quality engineer review points, confidence displays for operators, and documented override procedures.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (157, 'Deployment and monitoring specification', 'Model selection guidance, performance thresholds, production-aligned retraining triggers, and line-level monitoring requirements for production use.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (157, 'Which AI use cases are most commonly explored?', 'Predictive maintenance from vibration and temperature data, AI-powered visual defect detection, demand-based scheduling optimisation, and OEE anomaly alerting.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (157, 'What if our sensor infrastructure is limited?', 'The data readiness report identifies the minimum sensor coverage needed for each use case. Many plants start with predictive maintenance on high-value equipment while expanding coverage.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (157, 'How do quality engineers interact with AI inspection recommendations?', 'AI inspection results appear alongside images in the quality workflow with confidence scores. Engineers can confirm, override, or escalate, with all decisions logged for audit.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (157, 'How do we get started?', 'Book a consultation with the DigitalQatalyst team to identify your highest-value AI use cases and share your current sensor, MES, and quality data landscape.', 3);

-- Manufacturing Operations (High-Impact) - Deploy (variant 158)
UPDATE product_content SET
  description = 'Configure, integrate, and launch your manufacturing operations platform with structured testing across production, quality, and maintenance workflows, and a controlled handover that leaves your plant team ready to operate independently.',
  positioning = 'A managed deployment that takes your manufacturing blueprint from specification to a live, production-tested platform.',
  hero_summary = 'Configure, integrate, and launch your manufacturing operations platform with structured testing across production, quality, and maintenance workflows, and a controlled handover that leaves your plant team ready to operate independently.',
  overview_paragraphs = '["The Manufacturing Operations Deploy service delivers configured, tested capabilities with structured integration, quality assurance, and handover to your operations team. This implementation delivers configured, tested capabilities with structured handover.","Implement agreed manufacturing operations changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
  audience_description = 'Built for manufacturing & plant operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement delivers configured, tested, and validated manufacturing operations assets aligned to approved scope.","Each output supports go-live readiness and structured handover to your operations team."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Structured 12-week deployment with milestone-gated progress","Operator acceptance testing across all in-scope production lines","Hypercare support through the first weeks of live production"]'::jsonb,
  why_it_matters = '{"hook":"Manufacturing performance depends on synchronised production, quality control, and supply coordination.","problemParagraph":"Many organisations stall between approved designs and production for your manufacturing operations, with integration gaps, quality risks, and delayed go-live. This implementation delivers configured, tested capabilities with structured handover.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Stalled implementation","description":"Approved designs for manufacturing operations sit idle while teams struggle to coordinate build and integration."},{"title":"Quality and integration risk","description":"Testing gaps and platform dependencies threaten go-live timelines and stability."},{"title":"Unclear handover","description":"Operations teams lack the documentation and knowledge transfer needed to run live systems."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Production-ready delivery","description":"Capabilities are built, tested, and validated against agreed acceptance criteria."},{"title":"Integrated platforms","description":"Solutions are deployed with security, governance, and platform requirements met."},{"title":"Confident go-live","description":"Structured handover equips your teams to operate and evolve the capability."}]}}'::jsonb,
  faq_intro = 'Key questions about the manufacturing operations deployment.'
WHERE variant_id = 158;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (158, 'Configured manufacturing operations platform', 'Production-ready MES with scheduling, WIP tracking, quality control, and maintenance modules configured and tested against approved specifications.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (158, 'Integration test evidence pack', 'Test cases, execution results, and defect closure evidence for every connected system including ERP, SCADA, and maintenance management.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (158, 'Operator acceptance sign-off', 'Documented UAT results from operators, supervisors, and quality staff confirming the platform meets production requirements across all lines.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (158, 'Operational handover kit', 'Administrator guides, shift-change procedures, support escalation paths, and a 30-day post-launch review schedule.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (158, 'How do you minimise disruption to production during deployment?', 'Configuration and integration work is done in a staging environment. Cutover is scheduled during planned maintenance windows and validated with a parallel-run period before full go-live.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (158, 'What happens if sensor or SCADA integration issues are discovered during testing?', 'Integration issues are documented and triaged. The DigitalQatalyst team resolves issues within deployment scope. Changes affecting production infrastructure are escalated for separate planning.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (158, 'How are shift workers trained without impacting production targets?', 'Training sessions are scheduled around shift patterns. Role-specific quick-reference guides are available on the shop floor from day one of go-live.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (158, 'How do we get started?', 'Contact the DigitalQatalyst team to confirm the MES platform, integration scope, and production calendar constraints before deployment planning begins.', 3);

-- Manufacturing Operations (High-Impact) - AI Deploy (variant 159)
