  description = 'Deploy validated AI capabilities for predictive maintenance, visual quality inspection, and production scheduling into your live manufacturing environment, with real-time monitoring, engineer override controls, and a governance handover that keeps your plant team in control.',
  positioning = 'Put AI-powered maintenance, quality, and scheduling capabilities into production with the oversight controls your plant and quality teams require.',
  hero_summary = 'Deploy validated AI capabilities for predictive maintenance, visual quality inspection, and production scheduling into your live manufacturing environment, with real-time monitoring, engineer override controls, and a governance handover that keeps your plant team in control.',
  overview_paragraphs = '["The Manufacturing Operations AI Deploy service deploys governed AI capabilities into production with monitoring, safety controls, and operational handover. This AI implementation deploys governed capabilities with monitoring and handover built in.","Put AI-enabled manufacturing operations workflows into production with security, governance, and adoption built in from day one."]'::jsonb,
  audience_description = 'Built for manufacturing & plant operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement deploys production AI capabilities for manufacturing operations with monitoring and safety controls.","You receive operational runbooks and validation evidence before handover."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Pilot line rollout before full plant deployment","Override and feedback workflows embedded in existing plant systems","Retraining schedule and drift monitoring included in handover"]'::jsonb,
  why_it_matters = '{"hook":"Manufacturing performance depends on synchronised production, quality control, and supply coordination.","problemParagraph":"Many AI initiatives for your manufacturing operations fail to reach production, blocked by integration complexity, safety concerns, and missing operational readiness. This AI implementation deploys governed capabilities with monitoring and handover built in.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"AI stuck in pilot","description":"Promising AI designs for manufacturing operations fail to reach production due to integration and operational barriers."},{"title":"Safety and compliance gaps","description":"Monitoring, auditability, and responsible AI controls are not yet in place."},{"title":"Operational blind spots","description":"Teams lack runbooks and performance visibility for live AI capabilities."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Live AI capabilities","description":"AI is deployed in production with orchestration and monitoring built in."},{"title":"Governed operations","description":"Safety controls, compliance checks, and audit trails support responsible use at scale."},{"title":"Operational readiness","description":"Runbooks and handover materials equip teams to manage AI in production."}]}}'::jsonb,
  faq_intro = 'Key questions about the manufacturing operations AI deployment.'
WHERE variant_id = 159;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (159, 'Production manufacturing AI capabilities', 'Approved models live in your plant environment with sensor data pipelines, alert logging, and operator and engineer-facing interfaces active.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (159, 'Plant performance monitoring dashboard', 'Real-time view of model accuracy, maintenance prediction hit rates, visual inspection confidence, and production scheduling deviation by line.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (159, 'Engineer and operator override playbook', 'Procedures for accepting, overriding, and feeding back on AI recommendations, with escalation steps for model quality concerns.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (159, 'AI governance handover pack', 'Model cards, sensor data lineage, retraining schedule, and accountability assignments for ongoing responsible plant operation.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (159, 'How do maintenance technicians interact with predictive maintenance alerts?', 'Alerts surface in the maintenance management system with confidence scores, recommended actions, and one-click override. All actions are logged for model improvement.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (159, 'What happens if a predictive maintenance model produces frequent false alarms?', 'False-alarm rates are tracked in the monitoring dashboard. The DigitalQatalyst team adjusts model thresholds during the pilot phase before full plant rollout.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (159, 'How is model accuracy maintained as equipment ages or is replaced?', 'Retraining triggers are defined in the governance handover pack. Equipment change events automatically flag affected models for review and retraining.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (159, 'How do we get started?', 'Contact the DigitalQatalyst team with your approved AI design specification to plan the production environment, sensor pipeline access, and pilot line selection.', 3);

