INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (160, 'Monthly manufacturing performance report', 'OEE by line and shift, quality defect trends, maintenance adherence, and system health metrics with commentary and prioritised actions.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (160, 'Incident and change log', 'Transparent record of system incidents, configuration changes, and SLA performance across each reporting period.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (160, 'Quarterly plant optimisation review', 'Analysis of production bottlenecks, quality control gaps, and maintenance scheduling accuracy with prioritised improvement actions.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (160, 'Annual manufacturing technology roadmap', 'Forward-looking plan covering platform upgrades, new production line integrations, and capability additions aligned to the plant business plan.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (160, 'What is covered under the managed service?', 'Platform monitoring, incident response, configuration updates, monthly reporting, and quarterly optimisation reviews. Full scope is confirmed in the service agreement.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (160, 'How are configuration changes handled during production?', 'All configuration changes are tested in a staging environment and scheduled for production during planned maintenance windows, confirmed with plant leads in advance.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (160, 'Can the service scale to cover new production lines or sites?', 'Yes. New lines or sites are onboarded under the service. Large expansions are scoped and priced separately.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (160, 'How do we get started?', 'Contact the DigitalQatalyst team to confirm the platform scope, current configuration baseline, and production calendar before the service agreement is drafted.', 3);

-- Infrastructure Operations (High-Impact) - Assess (variant 161)
UPDATE product_content SET
  description = 'Identify where your infrastructure operations are creating asset reliability risk, maintenance planning gaps, or field productivity loss. The DigitalQatalyst team assesses operational maturity across your asset portfolio and returns a prioritised roadmap your asset and operations leaders can act on.',
  positioning = 'A structured assessment that shows where infrastructure asset gaps create reliability and service continuity risk, and what to prioritise first.',
  hero_summary = 'Identify where your infrastructure operations are creating asset reliability risk, maintenance planning gaps, or field productivity loss. The DigitalQatalyst team assesses operational maturity across your asset portfolio and returns a prioritised roadmap your asset and operations leaders can act on.',
  overview_paragraphs = '["The Infrastructure Operations Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps operational maturity and returns prioritised improvements your asset and operations leaders can act on.","See how infrastructure operations perform today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for asset managers & infrastructure leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews infrastructure operations across business operations and productivity.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Fixed-scope assessment delivered within one week","Covers asset visibility, maintenance, and field operations dimensions","No obligation to proceed with subsequent design or deployment"]'::jsonb,
  why_it_matters = '{"hook":"Infrastructure reliability depends on coordinated maintenance, safety controls, and asset visibility.","problemParagraph":"Many infrastructure operators manage assets with ageing systems, manual maintenance scheduling, and limited predictive insight. This assessment maps operational maturity and returns prioritised improvements your asset and operations leaders can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Fragmented operations data","description":"Infrastructure operations teams work from disconnected systems without a single operational view."},{"title":"Inconsistent field processes","description":"Standard operating procedures vary by site, team, or shift."},{"title":"Limited digitisation baseline","description":"Automation and analytics opportunities are unclear and unprioritised."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Operational priority map","description":"You know which infrastructure operations processes and systems to improve first."},{"title":"Ranked improvement backlog","description":"Gaps are ordered for design, technology, and investment."},{"title":"Leadership-ready roadmap","description":"Recommendations support governance review and transformation funding."}]}}'::jsonb,
  faq_intro = 'Key questions about the infrastructure operations assessment.'
WHERE variant_id = 161;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (161, 'Infrastructure operations maturity scorecard', 'Ratings across asset visibility, maintenance planning, field productivity, and service continuity controls, with evidence and specific gaps.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (161, 'Asset and maintenance gap report', 'Documented gaps in condition monitoring, work order management, parts planning, and field scheduling, ranked by reliability and service risk.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (161, 'Prioritised improvement roadmap', 'Sequenced actions with owners, effort estimates, and dependencies your operations team can act on within normal maintenance cycles.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (161, 'Leadership briefing pack', 'A concise summary of findings and recommended investment for asset management and operations leadership.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (161, 'What types of infrastructure assets does the assessment cover?', 'Utilities, transport, real estate, facilities, energy, and other asset-intensive environments. The DigitalQatalyst team confirms the asset classes in scope during scoping.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (161, 'Do you need access to our EAM or CMMS systems?', 'We review system-generated reports and asset records rather than live systems. Any access required is read-only and agreed in advance.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (161, 'What do we get at the end?', 'A maturity scorecard, an asset and maintenance gap report, a prioritised improvement roadmap, and a leadership briefing pack.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (161, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm the asset classes in scope, operational environment type, and key stakeholders before work begins.', 3);

-- Infrastructure Operations (High-Impact) - Design (variant 162)
UPDATE product_content SET
  description = 'Turn infrastructure operations improvement goals into a complete, build-ready blueprint: asset management workflows, maintenance scheduling logic, field workforce coordination specifications, and an adoption plan your operations teams can execute without ambiguity.',
  positioning = 'A design engagement that produces infrastructure operations specifications ready for EAM configuration and field rollout.',
  hero_summary = 'Turn infrastructure operations improvement goals into a complete, build-ready blueprint: asset management workflows, maintenance scheduling logic, field workforce coordination specifications, and an adoption plan your operations teams can execute without ambiguity.',
  overview_paragraphs = '["The Infrastructure Operations Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement defines infrastructure operations and build-ready specifications.","Turn infrastructure operations goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for asset managers & infrastructure leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate infrastructure operations requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Design-only engagement: no EAM or field management commitment required","Covers asset lifecycle, maintenance, and field workforce dimensions","Mobile and field-first design approach throughout"]'::jsonb,
  why_it_matters = '{"hook":"Infrastructure reliability depends on coordinated maintenance, safety controls, and asset visibility.","problemParagraph":"Many infrastructure programmes modernise operations without designed maintenance workflows, asset models, or specifications field teams can deploy. This design engagement defines infrastructure operations and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined operational workflows","description":"Infrastructure operations journeys from intake to completion are not designed end to end."},{"title":"Integration gaps","description":"Field, ERP, and customer systems lack clear data and event contracts."},{"title":"Rollout ambiguity","description":"Teams lack specs to pilot and scale changes across sites."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Aligned operational designs","description":"Workflows reflect how infrastructure operations teams actually deliver service."},{"title":"Consistent standards","description":"Data, integration, and governance requirements are defined upfront."},{"title":"Implementation-ready specs","description":"Delivery teams receive artefacts they can execute across locations."}]}}'::jsonb,
  faq_intro = 'Key questions about the infrastructure operations design engagement.'
WHERE variant_id = 162;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (162, 'Asset lifecycle workflow maps', 'End-to-end flows for inspection, condition recording, work order generation, field execution, and asset disposal across all in-scope asset classes.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (162, 'Maintenance scheduling specification', 'Preventive and condition-based maintenance rules by asset class and criticality, with production calendar and regulatory compliance integration.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (162, 'Field operations specification', 'Job scheduling logic, parts and materials management rules, and mobile completion recording requirements for field technicians.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (162, 'Operations adoption plan', 'Technician training requirements, mobile tool rollout sequence, and success metrics to track field adoption without disrupting service continuity.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (162, 'Does the design work with our existing EAM or CMMS platform?', 'Yes. The DigitalQatalyst team designs around your current platform, documenting configuration changes and integration updates needed to close the operational gaps identified.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (162, 'How are field technicians involved in the design process?', 'Field technicians and supervisors participate in workflow workshops to ensure job scheduling, parts management, and mobile recording flows work in real operating conditions.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (162, 'How do we get started?', 'Contact the DigitalQatalyst team to confirm the asset classes in scope, the EAM and field management platforms in use, and any regulatory compliance requirements.', 2);

-- Infrastructure Operations (High-Impact) - AI Design (variant 163)
UPDATE product_content SET
  description = 'Validate which AI use cases will genuinely improve asset reliability, maintenance scheduling, and field productivity before committing build budget. The DigitalQatalyst team designs responsible, audit-ready workflows and deployment-ready specifications for every approved infrastructure AI application.',
  positioning = 'Define and validate the AI capabilities that will improve asset uptime and field efficiency, with data readiness and responsible design confirmed before build.',
  hero_summary = 'Validate which AI use cases will genuinely improve asset reliability, maintenance scheduling, and field productivity before committing build budget. The DigitalQatalyst team designs responsible, audit-ready workflows and deployment-ready specifications for every approved infrastructure AI application.',
  overview_paragraphs = '["The Infrastructure Operations AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for infrastructure operations, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for asset managers & infrastructure leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for infrastructure operations.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Validates feasibility before any AI build investment is committed","Covers predictive failure, condition-based maintenance, and route optimisation AI","Responsible by design: engineer review gates at every decision point"]'::jsonb,
  why_it_matters = '{"hook":"Infrastructure reliability depends on coordinated maintenance, safety controls, and asset visibility.","problemParagraph":"Many organisations apply AI to your infrastructure operations without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for infrastructure operations lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for infrastructure operations are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Key questions about the infrastructure operations AI design engagement.'
WHERE variant_id = 163;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (163, 'Infrastructure AI use-case feasibility register', 'Each candidate scored on sensor data availability, asset history quality, and expected reliability or cost improvement, with a clear go or no-go recommendation.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (163, 'Asset data readiness report', 'Gaps in sensor coverage, inspection record completeness, maintenance history depth, and GIS data quality that must be addressed before model development.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (163, 'Responsible infrastructure AI workflows', 'Designed flows for approved use cases with engineer review points, confidence displays for field technicians, and documented override procedures.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (163, 'Deployment and monitoring specification', 'Model selection guidance, performance thresholds, asset-aligned retraining triggers, and fleet or portfolio-level monitoring requirements for production use.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (163, 'Which AI use cases are most commonly explored?', 'Predictive asset failure from sensor and maintenance history data, condition-based maintenance scheduling, field workforce route optimisation, and fault pattern detection across asset networks.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (163, 'What if our sensor coverage is limited to a subset of assets?', 'The data readiness report identifies the minimum coverage needed for each use case. Many organisations start with highest-criticality assets while expanding sensor coverage in parallel.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (163, 'How do field engineers interact with AI maintenance recommendations?', 'Recommendations appear in the field management mobile tool with confidence scores and recommended actions. Engineers can confirm, reschedule, or override, with all decisions logged.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (163, 'How do we get started?', 'Book a consultation with the DigitalQatalyst team to identify your highest-value AI use cases and share your current asset data, sensor, and maintenance record landscape.', 3);

-- Infrastructure Operations (High-Impact) - Deploy (variant 164)
