  hero_summary = 'Configure, integrate, and launch your infrastructure operations platform with structured testing across asset management, maintenance, and field workforce workflows, and a controlled handover that leaves your operations team ready to manage assets independently.',
  overview_paragraphs = '["The Infrastructure Operations Deploy service delivers configured, tested capabilities with structured integration, quality assurance, and handover to your operations team. This implementation delivers configured, tested capabilities with structured handover.","Implement agreed infrastructure operations changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
