INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (164, 'Configured infrastructure operations platform', 'Production-ready EAM with asset lifecycle management, maintenance scheduling, work order management, and field coordination configured and tested.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (164, 'Integration test evidence pack', 'Test cases, results, and defect closure evidence for every connected system including GIS, sensor networks, finance, and regulatory reporting.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (164, 'Field acceptance sign-off', 'Documented UAT results from technicians, supervisors, and asset managers confirming the platform meets operational requirements across all asset classes.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (164, 'Operational handover kit', 'Administrator guides, field supervisor quick-start pack, support escalation paths, and a 30-day post-launch review schedule.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (164, 'How do you handle asset data migration from legacy CMMS systems?', 'Asset data migration is included in the deployment scope. The DigitalQatalyst team validates data completeness and asset hierarchy accuracy before cutover.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (164, 'What happens if GIS or sensor integration issues are found during testing?', 'Issues are documented and triaged. The DigitalQatalyst team resolves items within deployment scope. Infrastructure or network issues are escalated for separate planning.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (164, 'How are mobile tools rolled out to field technicians?', 'Mobile device and application setup is included in the deployment. Field training sessions are scheduled to minimise service disruption.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (164, 'How do we get started?', 'Contact the DigitalQatalyst team to confirm the EAM platform, integration scope, asset data migration requirements, and field team size before deployment planning begins.', 3);

