WHERE variant_id = 166;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (166, 'Monthly asset health and maintenance report', 'Planned versus reactive maintenance ratios, work order completion rates, asset condition trends, and system health metrics with recommended actions.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (166, 'Incident and change log', 'Transparent record of platform incidents, configuration changes, and SLA performance across each reporting period.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (166, 'Quarterly infrastructure optimisation review', 'Analysis of maintenance scheduling accuracy, field workforce productivity, and asset reliability trends with prioritised improvement actions.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (166, 'Annual infrastructure technology roadmap', 'Forward-looking plan covering platform updates, new asset class integrations, and capability additions aligned to portfolio strategy and regulatory obligations.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (166, 'What is covered under the managed service?', 'Platform monitoring, incident response, configuration updates, monthly reporting, and quarterly optimisation reviews. Full scope is confirmed in the service agreement.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (166, 'How are regulatory compliance updates to maintenance standards handled?', 'Compliance-driven configuration changes are assessed, implemented in a test environment, validated, and promoted to production within the agreed change management process.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (166, 'Can the service scale to cover additional asset classes or new sites?', 'Yes. New asset classes and sites are onboarded under the service. Large portfolio expansions are scoped and priced separately.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (166, 'How do we get started?', 'Contact the DigitalQatalyst team to confirm the EAM platform, asset portfolio scope, and SLA requirements before the service agreement is drafted.', 3);

-- Government Operations (High-Impact) - Assess (variant 167)
UPDATE product_content SET
  description = 'Identify where your government operations and citizen services are creating processing backlogs, transparency gaps, or cross-agency coordination failures. The DigitalQatalyst team assesses operational maturity and returns a prioritised roadmap your programme leaders can act on.',
  positioning = 'A structured assessment that reveals where government operational gaps reduce citizen service quality and what to address first.',
  hero_summary = 'Identify where your government operations and citizen services are creating processing backlogs, transparency gaps, or cross-agency coordination failures. The DigitalQatalyst team assesses operational maturity and returns a prioritised roadmap your programme leaders can act on.',
  overview_paragraphs = '["The Government Operations Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps operational maturity and returns prioritised improvements programme leaders can act on.","See how government operations and citizen services perform today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for public sector & digital government leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews government operations across business operations and productivity.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Fixed-scope assessment delivered within one week","Covers citizen service, back-office, and cross-agency dimensions","No obligation to proceed with subsequent design or deployment"]'::jsonb,
  why_it_matters = '{"hook":"Public service delivery depends on reliable processes, transparent accountability, and citizen-centred design.","problemParagraph":"Many public sector bodies run services with legacy processes, siloed data, and limited visibility into citizen journey performance. This assessment maps operational maturity and returns prioritised improvements programme leaders can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Fragmented operations data","description":"Government service teams work from disconnected systems without a single operational view."},{"title":"Inconsistent field processes","description":"Standard operating procedures vary by site, team, or shift."},{"title":"Limited digitisation baseline","description":"Automation and analytics opportunities are unclear and unprioritised."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Operational priority map","description":"You know which government service processes and systems to improve first."},{"title":"Ranked improvement backlog","description":"Gaps are ordered for design, technology, and investment."},{"title":"Leadership-ready roadmap","description":"Recommendations support governance review and transformation funding."}]}}'::jsonb,
  faq_intro = 'Key questions about the government operations assessment.'
WHERE variant_id = 167;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (167, 'Government operations maturity scorecard', 'Ratings across citizen service delivery, back-office processing, cross-agency coordination, and transparency controls, with evidence and specific gaps.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (167, 'Service delivery gap report', 'Documented process bottlenecks, coordination failures, and compliance control gaps ranked by citizen impact and operational risk.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (167, 'Prioritised improvement roadmap', 'Sequenced actions with named owners, effort estimates, and dependencies your programme team can act on within normal governance cycles.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (167, 'Leadership and ministerial briefing pack', 'A concise summary of findings and recommended investment for digital government and programme leadership.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (167, 'Which government functions does the assessment cover?', 'The scope is confirmed with your programme leads before engagement. Common areas include licensing, grants, permits, benefits processing, and case management.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (167, 'Do you need access to case management or citizen data systems?', 'We review process documentation and system outputs rather than live citizen data. Any access required is read-only, data-minimised, and agreed with your data governance lead in advance.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (167, 'What do we get at the end?', 'A maturity scorecard, a service delivery gap report, a prioritised improvement roadmap, and a leadership briefing pack.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (167, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm the services and functions in scope, data access constraints, and key stakeholders before work begins.', 3);

-- Government Operations (High-Impact) - Design (variant 168)
UPDATE product_content SET
  description = 'Turn government operations and citizen service improvement goals into a complete, build-ready blueprint: service journey designs, back-office workflow specifications, cross-agency integration patterns, and an adoption plan your delivery teams can execute within public sector governance.',
  positioning = 'A design engagement that produces government operations and citizen service specifications ready for platform configuration and delivery.',
  hero_summary = 'Turn government operations and citizen service improvement goals into a complete, build-ready blueprint: service journey designs, back-office workflow specifications, cross-agency integration patterns, and an adoption plan your delivery teams can execute within public sector governance.',
  overview_paragraphs = '["The Government Operations Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement defines government operations and build-ready specifications.","Turn government operations and citizen services goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for public sector & digital government leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate government operations requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Design-only engagement: no platform commitment required","Privacy and regulatory compliance built into every integration design","Citizen accessibility standards addressed throughout the design"]'::jsonb,
  why_it_matters = '{"hook":"Public service delivery depends on reliable processes, transparent accountability, and citizen-centred design.","problemParagraph":"Many government programmes digitise services without designed citizen journeys, policy controls, or specifications delivery teams can implement. This design engagement defines government operations and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined operational workflows","description":"Government service journeys from intake to completion are not designed end to end."},{"title":"Integration gaps","description":"Field, ERP, and customer systems lack clear data and event contracts."},{"title":"Rollout ambiguity","description":"Teams lack specs to pilot and scale changes across sites."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Aligned operational designs","description":"Workflows reflect how government service teams actually deliver service."},{"title":"Consistent standards","description":"Data, integration, and governance requirements are defined upfront."},{"title":"Implementation-ready specs","description":"Delivery teams receive artefacts they can execute across locations."}]}}'::jsonb,
  faq_intro = 'Key questions about the government operations design engagement.'
WHERE variant_id = 168;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (168, 'Citizen journey maps', 'End-to-end service flows from initial application through processing, decision, notification, and appeals across all in-scope government services.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (168, 'Back-office workflow specification', 'Approval queues, case assignment rules, compliance check procedures, and audit trail requirements documented for configuration and development teams.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (168, 'Cross-agency integration design', 'Data sharing patterns, referral workflow logic, and privacy compliance controls for all inter-agency touchpoints in scope.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (168, 'Public sector adoption plan', 'Phased rollout sequence with staff training requirements by role, accessibility compliance checklist, and service continuity plan during transition.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (168, 'How do you ensure the design meets accessibility obligations?', 'Accessibility requirements are incorporated from the first workshop. The DigitalQatalyst team aligns designs to the applicable standard, such as WCAG 2.1 AA, and documents compliance evidence.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (168, 'How are citizens involved in the design process?', 'Where the programme governance permits, representative citizen research or usability review is incorporated to validate that service journeys work for the intended audience.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (168, 'How do we get started?', 'Contact the DigitalQatalyst team to confirm the services and functions in scope, the platforms in use, and any procurement or governance constraints before the engagement begins.', 2);

-- Government Operations (High-Impact) - AI Design (variant 169)
UPDATE product_content SET
  description = 'Validate where AI can improve government service processing speed, decision support, and cross-agency coordination before committing build budget. The DigitalQatalyst team designs responsible, audit-ready AI workflows and deployment-ready specifications that meet public sector accountability requirements.',
  positioning = 'Define and validate the AI use cases that will improve citizen service quality and processing efficiency, with responsible design and public sector accountability built in.',
  hero_summary = 'Validate where AI can improve government service processing speed, decision support, and cross-agency coordination before committing build budget. The DigitalQatalyst team designs responsible, audit-ready AI workflows and deployment-ready specifications that meet public sector accountability requirements.',
  overview_paragraphs = '["The Government Operations AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for government operations and citizen services, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for public sector & digital government leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for government operations.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Validates feasibility and regulatory permissibility before any build investment","Responsible by design: case officer review, explainability, and citizen appeal rights built in","Aligned to public sector AI accountability and transparency requirements"]'::jsonb,
  why_it_matters = '{"hook":"Public service delivery depends on reliable processes, transparent accountability, and citizen-centred design.","problemParagraph":"Many organisations apply AI to your government services without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for government operations lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for government operations are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Key questions about the government operations AI design engagement.'
WHERE variant_id = 169;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (169, 'Government AI use-case feasibility register', 'Each candidate scored on data availability, regulatory permissibility, and expected service quality or processing efficiency improvement, with a go or no-go recommendation.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (169, 'Government data readiness report', 'Gaps in case management data quality, document classification coverage, and inter-agency sharing agreements that must be resolved before model development.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (169, 'Responsible government AI workflows', 'Designed flows for approved use cases with case officer review points, citizen-facing explainability, appeal rights preserved, and audit logging at every decision point.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (169, 'Public sector AI deployment specification', 'Model selection guidance, bias testing requirements, performance thresholds, audit log design, and accountability assignments aligned to applicable public sector AI policy.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (169, 'Which AI use cases are most commonly explored in government?', 'Automated eligibility pre-screening, intelligent document classification, risk-based case prioritisation, and back-office processing queue optimisation are the most common starting points.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (169, 'How do you handle the legal and policy requirements for automated government decisions?', 'Accountability, explainability, and citizen appeal rights are designed into every workflow from the start. The DigitalQatalyst team confirms the applicable legal framework during scoping.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (169, 'What if citizen data cannot be used for AI model training?', 'Synthetic data, anonymised record sets, and privacy-preserving training techniques are explored during the data readiness phase. Use cases requiring live citizen data are flagged for separate legal review.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (169, 'How do we get started?', 'Book a consultation with the DigitalQatalyst team to identify your highest-value AI use cases and confirm data availability, legal constraints, and programme governance requirements.', 3);

-- Government Operations (High-Impact) - Deploy (variant 170)
UPDATE product_content SET
  description = 'Configure, integrate, and launch your government operations and citizen service platform with structured testing across service delivery, back-office, and cross-agency workflows, and a controlled handover that leaves your programme team ready to operate within public sector governance.',
  positioning = 'A managed deployment that takes your government operations blueprint from specification to a live, tested platform that meets public sector delivery and compliance requirements.',
  hero_summary = 'Configure, integrate, and launch your government operations and citizen service platform with structured testing across service delivery, back-office, and cross-agency workflows, and a controlled handover that leaves your programme team ready to operate within public sector governance.',
  overview_paragraphs = '["The Government Operations Deploy service delivers configured, tested capabilities with structured integration, quality assurance, and handover to your operations team. This implementation delivers configured, tested capabilities with structured handover.","Implement agreed government operations and citizen services changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
  audience_description = 'Built for public sector & digital government leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement delivers configured, tested, and validated government operations assets aligned to approved scope.","Each output supports go-live readiness and structured handover to your operations team."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Structured 12-week deployment with milestone-gated progress","Accessibility and compliance validation included in acceptance testing","Hypercare support through the first weeks of live citizen service operation"]'::jsonb,
  why_it_matters = '{"hook":"Public service delivery depends on reliable processes, transparent accountability, and citizen-centred design.","problemParagraph":"Many organisations stall between approved designs and production for your government services, with integration gaps, quality risks, and delayed go-live. This implementation delivers configured, tested capabilities with structured handover.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Stalled implementation","description":"Approved designs for government operations sit idle while teams struggle to coordinate build and integration."},{"title":"Quality and integration risk","description":"Testing gaps and platform dependencies threaten go-live timelines and stability."},{"title":"Unclear handover","description":"Operations teams lack the documentation and knowledge transfer needed to run live systems."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Production-ready delivery","description":"Capabilities are built, tested, and validated against agreed acceptance criteria."},{"title":"Integrated platforms","description":"Solutions are deployed with security, governance, and platform requirements met."},{"title":"Confident go-live","description":"Structured handover equips your teams to operate and evolve the capability."}]}}'::jsonb,
  faq_intro = 'Key questions about the government operations deployment.'
