INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (171, 'Production government AI capabilities', 'Approved models live in your government operations platform with data pipelines, decision logging, and case officer-facing recommendation interfaces active.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (171, 'Service performance monitoring dashboard', 'Real-time view of model accuracy, case officer override rates, processing time improvement, and bias indicators by service line and demographic group.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (171, 'Case officer override and appeal playbook', 'Procedures for accepting, overriding, and escalating AI recommendations, with citizen explanation and appeal right documentation for each service.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (171, 'Public sector AI governance handover pack', 'Model cards, data lineage documentation, bias testing records, quarterly accountability review schedule, and accountability assignments for ongoing responsible operation.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (171, 'How do case officers override AI recommendations?', 'Override controls are built into the case management interface. All overrides are logged with a reason and reviewed in the quarterly accountability session.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (171, 'How do you monitor for bias in AI-assisted government decisions?', 'Demographic group outcome analysis runs continuously in the monitoring dashboard. Disparity alerts trigger immediate review and, where needed, model adjustment before the next processing cycle.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (171, 'What happens if AI recommendations are challenged through a citizen appeal?', 'Decision logs, model outputs, and case officer actions are retrievable through the audit trail to support the appeals process. The accountability playbook covers the specific steps for each service.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (171, 'How do we get started?', 'Contact the DigitalQatalyst team with your approved AI design specification to plan the production environment, data pipeline access, and pilot service line selection.', 3);

