  hero_summary = 'A governed AI deployment that puts validated hospitality AI capabilities into production with integrated monitoring, safety controls, staff enablement, and a formal operational handover.',
  overview_paragraphs = '["The Hospitality Operations AI Deploy service deploys governed AI capabilities into production with monitoring, safety controls, and operational handover. This AI implementation deploys governed capabilities with monitoring and handover built in.","Put AI-enabled hospitality operations and guest experience workflows into production with security, governance, and adoption built in from day one."]'::jsonb,
