  deliverables_summary = '["This engagement deploys production AI capabilities for hospitality operations with monitoring and safety controls.","You receive operational runbooks and validation evidence before handover."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Shadow-mode testing validates AI accuracy against live data before guest-facing activation","Staff override controls built into every AI-assisted workflow from launch day","Monitoring dashboards cover both model health and guest-experience outcomes"]'::jsonb,
  why_it_matters = '{"hook":"Guest experience in hospitality is shaped by every operational handoff, from booking to checkout.","problemParagraph":"Many AI initiatives for your hospitality operations fail to reach production, blocked by integration complexity, safety concerns, and missing operational readiness. This AI implementation deploys governed capabilities with monitoring and handover built in.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"AI stuck in pilot","description":"Promising AI designs for hospitality operations fail to reach production due to integration and operational barriers."},{"title":"Safety and compliance gaps","description":"Monitoring, auditability, and responsible AI controls are not yet in place."},{"title":"Operational blind spots","description":"Teams lack runbooks and performance visibility for live AI capabilities."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Live AI capabilities","description":"AI is deployed in production with orchestration and monitoring built in."},{"title":"Governed operations","description":"Safety controls, compliance checks, and audit trails support responsible use at scale."},{"title":"Operational readiness","description":"Runbooks and handover materials equip teams to manage AI in production."}]}}'::jsonb,
  faq_intro = 'Key questions about deploying AI into live hospitality operations.'
WHERE variant_id = 177;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (177, 'Live AI capability suite', 'Approved AI features in production, integrated with your PMS, guest-data sources, and operational workflows, tested and accepted by department leads.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (177, 'Monitoring and alerting dashboard', 'Real-time view of model performance, guest-experience impact metrics, and operational KPIs, with alert thresholds set to your agreed tolerances.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (177, 'Governance and override documentation', 'Written policies and in-system controls covering when staff must override AI recommendations, escalation paths, and incident-response procedures.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (177, 'AI operations handover pack', 'Model cards, integration diagrams, monitoring runbooks, and retraining schedules handed to your technology and operations teams.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (177, 'Which AI capabilities are typically deployed in this engagement?', 'Those validated in the AI Design phase: commonly personalisation engines, predictive housekeeping scheduling, demand forecasting, and AI-assisted concierge. Scope is confirmed from your approved specifications.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (177, 'How do you prevent AI errors from affecting guests?', 'Shadow-mode testing runs the models against live data without acting on outputs until performance thresholds are met. Staff override controls remain active after launch.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (177, 'Who owns the AI models after handover?', 'Your technology team, with the DigitalQatalyst team providing model cards, monitoring documentation, and retraining schedules as part of the handover pack.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (177, 'How do we get started?', 'Provide your approved AI deployment specifications and the DigitalQatalyst team will confirm the production environment requirements and phased activation plan.', 3);

-- Hospitality Operations (High-Impact) - Managed (variant 178)
UPDATE product_content SET
  description = 'An ongoing managed service that runs and continuously improves your hospitality operations platform, with SLA-backed monitoring, monthly performance reporting, and proactive optimisation by the DigitalQatalyst team.',
  positioning = 'Keep hospitality operations performing at their best with continuous monitoring, expert optimisation, and a team who knows your property.',
  hero_summary = 'An ongoing managed service that runs and continuously improves your hospitality operations platform, with SLA-backed monitoring, monthly performance reporting, and proactive optimisation by the DigitalQatalyst team.',
  overview_paragraphs = '["The Hospitality Operations Managed Service service runs SLA-backed operations with continuous monitoring, optimisation, and lifecycle governance. This managed service provides SLA-backed operations and continuous improvement.","Run and improve hospitality operations and guest experience with ongoing monitoring, reporting, and optimisation so performance keeps pace with your business."]'::jsonb,
  audience_description = 'Built for hospitality & guest experience leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This managed service covers ongoing operations, reporting, and improvement for hospitality operations - managed.","You receive predictable SLA-backed support aligned to agreed service levels."]'::jsonb,
  delivery_process = '{"totalDuration":"Ongoing","steps":[{"step":1,"title":"Onboard","duration":"Week 1","body":"We align on scope, SLAs, access, and how we will run the service with your team.","whatHappens":"Scope alignment, SLA setup, and access provisioning","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Operate","duration":"Ongoing","body":"We run agreed operations with monitoring, incident response, and SLA-backed reporting.","whatHappens":"Monitoring, incident response, and service reporting","dqEffort":"high","yourEffort":"low"},{"step":3,"title":"Improve","duration":"Ongoing","body":"We review performance, apply optimisations, and keep the service aligned as your needs change.","whatHappens":"Performance reviews, optimisations, and roadmap updates","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Named service team with hospitality-sector context, not a rotating support pool","Proactive optimisation included, not just reactive incident response","Monthly reporting gives leadership visibility without requiring internal analyst time"]'::jsonb,
  why_it_matters = '{"hook":"Guest experience in hospitality is shaped by every operational handoff, from booking to checkout.","problemParagraph":"Many organisations struggle to sustain performance across your hospitality operations after go-live, with reactive support, rising costs, and declining platform value. This managed service provides SLA-backed operations and continuous improvement.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive operations","description":"hospitality operations issues are addressed after impact, not prevented through proactive management."},{"title":"Declining performance","description":"Platform value erodes without continuous optimisation and lifecycle governance."},{"title":"Unpredictable support","description":"Service levels and escalation paths are unclear when teams need help most."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"SLA-backed operations","description":"Predictable service levels and structured incident management keep platforms running."},{"title":"Continuous optimisation","description":"Proactive monitoring and improvement sustain performance and user satisfaction."},{"title":"Lifecycle governance","description":"Regular reviews and reporting align platform evolution with business priorities."}]}}'::jsonb,
  faq_intro = 'Key questions about the Hospitality Operations managed service.'
WHERE variant_id = 178;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (178, 'Monthly performance report', 'Guest satisfaction scores, system uptime, service throughput, and trend analysis across all monitored platforms, delivered every month.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (178, 'Optimisation log', 'Record of every configuration change, workflow adjustment, and integration fix made during the service period, with outcomes noted.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (178, 'SLA compliance report', 'Monthly record of incidents, response times, and resolution times against agreed SLA targets, with root-cause notes for any breaches.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (178, 'Annual service roadmap', 'Forward-looking plan identifying optimisation priorities, technology refresh opportunities, and recommended investments for the next 12 months.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (178, 'What does the managed service cover?', 'Monitoring, incident response, and proactive optimisation of your hospitality operations platform, including PMS, POS, and guest-communication integrations. Exact scope is agreed during onboarding.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (178, 'What SLAs apply?', 'Response and resolution targets are confirmed during onboarding based on your platform criticality. Guest-facing system incidents receive priority-one treatment.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (178, 'Can the service expand to cover new systems added after launch?', 'Yes. The DigitalQatalyst team can onboard additional platforms into the managed scope as your technology estate grows.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (178, 'How do we get started?', 'Contact the DigitalQatalyst team to schedule a service onboarding call. We confirm the systems in scope, SLA targets, reporting format, and the named contacts on both sides.', 3);

-- Retail Operations (High-Impact) - Assess (variant 179)
UPDATE product_content SET
  description = 'A targeted assessment of your retail and omnichannel operations that identifies the gaps in store productivity, inventory visibility, and sales execution that are costing you revenue and customer loyalty.',
  positioning = 'Understand exactly where your retail operations fall short, and walk away with a prioritised action plan your store and commerce leaders can execute.',
  hero_summary = 'A targeted assessment of your retail and omnichannel operations that identifies the gaps in store productivity, inventory visibility, and sales execution that are costing you revenue and customer loyalty.',
  overview_paragraphs = '["The Retail Operations Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps operational maturity and returns prioritised improvements your retail leaders can act on.","See how retail operations and omnichannel commerce perform today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for retail, commerce & store operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews retail operations across business operations and productivity.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Covers in-store, online, and omnichannel flows in a single assessment","Revenue-impact scoring on every recommendation, not just operational priority","Fixed-scope with findings ready for leadership review within the week"]'::jsonb,
  why_it_matters = '{"hook":"Retail success depends on consistent store execution, inventory accuracy, and connected customer journeys.","problemParagraph":"Many retailers run stores and channels with inconsistent stock visibility, promotional execution, and customer handoffs. This assessment maps operational maturity and returns prioritised improvements your retail leaders can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Fragmented operations data","description":"Retail operations teams work from disconnected systems without a single operational view."},{"title":"Inconsistent field processes","description":"Standard operating procedures vary by site, team, or shift."},{"title":"Limited digitisation baseline","description":"Automation and analytics opportunities are unclear and unprioritised."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Operational priority map","description":"You know which retail operations processes and systems to improve first."},{"title":"Ranked improvement backlog","description":"Gaps are ordered for design, technology, and investment."},{"title":"Leadership-ready roadmap","description":"Recommendations support governance review and transformation funding."}]}}'::jsonb,
  faq_intro = 'Key questions about the Retail Operations assessment.'
WHERE variant_id = 179;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (179, 'Omnichannel operations audit', 'A channel-by-channel review of customer journey friction points, handoff failures, and inventory inconsistencies with root causes and impact estimates.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (179, 'Inventory visibility report', 'Assessment of real-time stock accuracy across stores, warehouses, and digital channels, with the gaps creating lost sales or excess markdown.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (179, 'Store productivity scorecard', 'Benchmark of task completion rates, scheduling efficiency, and service standards across your estate, with the highest-leverage improvement opportunities identified.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (179, 'Prioritised action roadmap', 'Sequenced improvement actions ranked by revenue impact and delivery effort, with suggested ownership and a phasing recommendation for your leadership team.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (179, 'How many stores or channels does the assessment cover?', 'Scope is confirmed with the DigitalQatalyst team before the engagement starts. Typically one to three representative store formats and your primary digital channel are included.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (179, 'What data do you need access to?', 'Sales reports, inventory records, and operational metrics. No customer PII is required. Data access is read-only and agreed in advance.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (179, 'Do you cover both physical retail and e-commerce?', 'Yes. The assessment maps the customer journey across all channels your business operates, including click-and-collect and returns flows.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (179, 'How do we get started?', 'Request a consultation with the DigitalQatalyst team. We confirm the channels in scope, the data required, and the assessment schedule.', 3);

-- Retail Operations (High-Impact) - Design (variant 180)
UPDATE product_content SET
  description = 'A design engagement that converts your retail operations objectives into customer-centred journey designs, inventory workflow specifications, and technology integration blueprints your implementation teams can build and release.',
  positioning = 'Design the retail operations blueprint your teams need: customer journeys, inventory workflows, and system integrations ready for build.',
  hero_summary = 'A design engagement that converts your retail operations objectives into customer-centred journey designs, inventory workflow specifications, and technology integration blueprints your implementation teams can build and release.',
  overview_paragraphs = '["The Retail Operations Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement defines retail operations and build-ready specifications.","Turn retail operations and omnichannel commerce goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for retail, commerce & store operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate retail operations requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Customer journey and back-office workflow design completed in a single sprint","Integration architecture built to your existing POS, OMS, and WMS systems","Rollout plan included so delivery teams have sequencing from the start"]'::jsonb,
  why_it_matters = '{"hook":"Retail success depends on consistent store execution, inventory accuracy, and connected customer journeys.","problemParagraph":"Many retail groups upgrade commerce and store systems without designed omnichannel workflows, inventory models, or specifications teams can roll out. This design engagement defines retail operations and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined operational workflows","description":"Retail operations journeys from intake to completion are not designed end to end."},{"title":"Integration gaps","description":"Field, ERP, and customer systems lack clear data and event contracts."},{"title":"Rollout ambiguity","description":"Teams lack specs to pilot and scale changes across sites."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Aligned operational designs","description":"Workflows reflect how retail operations teams actually deliver service."},{"title":"Consistent standards","description":"Data, integration, and governance requirements are defined upfront."},{"title":"Implementation-ready specs","description":"Delivery teams receive artefacts they can execute across locations."}]}}'::jsonb,
  faq_intro = 'Key questions about the Retail Operations design engagement.'
WHERE variant_id = 180;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (180, 'Omnichannel journey designs', 'Detailed customer journey maps for each channel and segment, with service standards, touchpoints, and consistency checkpoints across store and digital surfaces.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (180, 'Inventory and order workflow specifications', 'Step-by-step process definitions for receiving, picking, packing, fulfilment, and returns, designed to eliminate the handoff errors identified in assessment.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (180, 'Technology integration architecture', 'Data-flow diagrams and integration specifications connecting POS, OMS, WMS, and customer-data platforms into a coherent retail operations picture.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (180, 'Adoption and rollout plan', 'Store-by-store and channel-by-channel rollout sequence with training materials, communication templates, and go/no-go criteria for each phase.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (180, 'Can we run the design engagement without completing an assessment first?', 'Yes, if you have clear objectives and existing operational data. The DigitalQatalyst team will confirm whether a design-only engagement is appropriate during scoping.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (180, 'Does the design cover both store and digital channels?', 'Yes. Journey designs and workflow specifications cover every channel in scope, including click-and-collect, ship-from-store, and returns.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (180, 'What format are the specifications delivered in?', 'Annotated journey maps, workflow diagrams, and integration specs delivered in a shared digital workspace formatted for handover to internal or third-party delivery teams.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (180, 'How do we get started?', 'Book a scoping call and the DigitalQatalyst team will confirm the channels in scope, the workshops required, and the design sprint schedule.', 3);

-- Retail Operations (High-Impact) - AI Design (variant 181)
UPDATE product_content SET
  description = 'A retail-focused AI design engagement that validates which AI use cases will genuinely improve sales execution, inventory accuracy, and customer engagement, producing responsible workflow designs and build-ready specifications before any development begins.',
  positioning = 'Design AI for retail with evidence-backed use cases, clean data requirements, and responsible-AI guardrails agreed before a line of code is written.',
  hero_summary = 'A retail-focused AI design engagement that validates which AI use cases will genuinely improve sales execution, inventory accuracy, and customer engagement, producing responsible workflow designs and build-ready specifications before any development begins.',
  overview_paragraphs = '["The Retail Operations AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for retail operations and omnichannel commerce, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for retail, commerce & store operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for retail operations.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Use-case validation against your actual retail data, not generic benchmarks","Pricing and markdown AI designs include mandatory human-override controls","Deployment specifications are ready to hand to your engineering or vendor team"]'::jsonb,
  why_it_matters = '{"hook":"Retail success depends on consistent store execution, inventory accuracy, and connected customer journeys.","problemParagraph":"Many organisations apply AI to your retail operations without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for retail operations lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for retail operations are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Key questions about designing AI capabilities for retail operations.'
WHERE variant_id = 181;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (181, 'Validated retail AI use-case register', 'Candidate AI use cases scored against commercial value, data availability, regulatory constraints, and responsible-AI criteria specific to retail.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (181, 'Responsible workflow designs', 'Step-by-step AI-assisted workflow specifications for approved use cases, with pricing override controls, human-review triggers, and escalation paths.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (181, 'Retail data readiness report', 'Assessment of transactional, inventory, and customer-behaviour data required for each approved AI use case, with gaps and remediation steps.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (181, 'AI deployment specification', 'Build-ready documentation covering model selection, integration points, monitoring metrics, and rollback procedures for each approved retail AI use case.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (181, 'What AI use cases are most common in retail?', 'Demand forecasting, personalised product recommendations, dynamic markdown optimisation, inventory replenishment triggers, and AI-assisted loss prevention. The DigitalQatalyst team validates which are feasible for your data estate.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (181, 'Do we need a unified data platform before starting?', 'No. The data readiness assessment identifies what you have and what gaps need closing. Some use cases may be ready to build immediately; others need data infrastructure work first.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (181, 'How do you handle pricing AI responsibly?', 'Pricing and markdown AI workflow designs include mandatory human-review stages and override controls. We specify the governance process before any build investment is made.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (181, 'How do we get started?', 'Request a scoping call and the DigitalQatalyst team will confirm which AI use cases to evaluate and what data access is required for the feasibility assessment.', 3);

-- Retail Operations (High-Impact) - Deploy (variant 182)
UPDATE product_content SET
  description = 'A managed retail operations deployment that configures, integrates, tests, and launches your omnichannel commerce platform capabilities, with structured quality assurance and a formal handover to your store and digital operations teams.',
  positioning = 'Launch retail operations improvements across store and digital channels with a tested build, structured rollout, and confirmed team handover.',
  hero_summary = 'A managed retail operations deployment that configures, integrates, tests, and launches your omnichannel commerce platform capabilities, with structured quality assurance and a formal handover to your store and digital operations teams.',
  overview_paragraphs = '["The Retail Operations Deploy service delivers configured, tested capabilities with structured integration, quality assurance, and handover to your operations team. This implementation delivers configured, tested capabilities with structured handover.","Implement agreed retail operations and omnichannel commerce changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
  audience_description = 'Built for retail, commerce & store operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement delivers configured, tested, and validated retail operations assets aligned to approved scope.","Each output supports go-live readiness and structured handover to your operations team."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Channel-by-channel acceptance testing with formal sign-off before any customer traffic","Phased launch sequence reduces the risk of large-scale disruption at go-live","Hypercare support covers the first weeks of live omnichannel operation"]'::jsonb,
  why_it_matters = '{"hook":"Retail success depends on consistent store execution, inventory accuracy, and connected customer journeys.","problemParagraph":"Many organisations stall between approved designs and production for your retail operations, with integration gaps, quality risks, and delayed go-live. This implementation delivers configured, tested capabilities with structured handover.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Stalled implementation","description":"Approved designs for retail operations sit idle while teams struggle to coordinate build and integration."},{"title":"Quality and integration risk","description":"Testing gaps and platform dependencies threaten go-live timelines and stability."},{"title":"Unclear handover","description":"Operations teams lack the documentation and knowledge transfer needed to run live systems."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Production-ready delivery","description":"Capabilities are built, tested, and validated against agreed acceptance criteria."},{"title":"Integrated platforms","description":"Solutions are deployed with security, governance, and platform requirements met."},{"title":"Confident go-live","description":"Structured handover equips your teams to operate and evolve the capability."}]}}'::jsonb,
  faq_intro = 'Key questions about the Retail Operations deployment engagement.'
WHERE variant_id = 182;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (182, 'Configured retail operations platform', 'POS, OMS, and WMS configured and integrated across your in-scope channels and store formats, with data flows tested end-to-end.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (182, 'Test results and channel sign-off report', 'Test evidence covering integration, fulfilment workflow, and acceptance scenarios for each channel, with all critical issues resolved pre-launch.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (182, 'Staff training completion record', 'Documented training completion by store format, role, and digital-operations function, with competency assessed against operational standards.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (182, 'Retail operations handover pack', 'System configuration documentation, runbooks, escalation contacts, and first-90-days operational guidance for store operations and digital teams.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (182, 'Can we deploy store and online channels simultaneously?', 'Usually not recommended. The DigitalQatalyst team designs a phased channel sequence that lets you validate in-store operation before activating digital fulfilment flows.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (182, 'How is existing inventory data migrated?', 'Migration is planned, validated, and tested in a non-production environment before go-live. The migration approach is confirmed with your operations team during weeks one to three.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (182, 'What if acceptance testing reveals issues with a specific store format?', 'Issues are logged, triaged, and resolved before that format proceeds to launch. Go-live gates are format-specific so a delay in one store type does not hold back others.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (182, 'How do we get started?', 'Share your approved design specifications with the DigitalQatalyst team and we will scope the deployment plan and environment requirements.', 3);

-- Retail Operations (High-Impact) - AI Deploy (variant 183)
UPDATE product_content SET
  description = 'A governed AI deployment that puts validated retail AI capabilities into production with integrated monitoring, merchandising-safe override controls, and a formal handover to your retail operations and technology teams.',
  positioning = 'Activate retail AI in a controlled, monitored way that protects pricing integrity, inventory accuracy, and customer trust from launch day.',
  hero_summary = 'A governed AI deployment that puts validated retail AI capabilities into production with integrated monitoring, merchandising-safe override controls, and a formal handover to your retail operations and technology teams.',
  overview_paragraphs = '["The Retail Operations AI Deploy service deploys governed AI capabilities into production with monitoring, safety controls, and operational handover. This AI implementation deploys governed capabilities with monitoring and handover built in.","Put AI-enabled retail operations and omnichannel commerce workflows into production with security, governance, and adoption built in from day one."]'::jsonb,
  audience_description = 'Built for retail, commerce & store operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement deploys production AI capabilities for retail operations with monitoring and safety controls.","You receive operational runbooks and validation evidence before handover."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Shadow-mode testing validates model accuracy against live retail data before any commercial impact","Merchandising override controls active from day one of live operation","Use-case-by-use-case activation schedule reduces risk at each launch gate"]'::jsonb,
  why_it_matters = '{"hook":"Retail success depends on consistent store execution, inventory accuracy, and connected customer journeys.","problemParagraph":"Many AI initiatives for your retail operations fail to reach production, blocked by integration complexity, safety concerns, and missing operational readiness. This AI implementation deploys governed capabilities with monitoring and handover built in.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"AI stuck in pilot","description":"Promising AI designs for retail operations fail to reach production due to integration and operational barriers."},{"title":"Safety and compliance gaps","description":"Monitoring, auditability, and responsible AI controls are not yet in place."},{"title":"Operational blind spots","description":"Teams lack runbooks and performance visibility for live AI capabilities."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Live AI capabilities","description":"AI is deployed in production with orchestration and monitoring built in."},{"title":"Governed operations","description":"Safety controls, compliance checks, and audit trails support responsible use at scale."},{"title":"Operational readiness","description":"Runbooks and handover materials equip teams to manage AI in production."}]}}'::jsonb,
  faq_intro = 'Key questions about deploying AI into live retail operations.'
WHERE variant_id = 183;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (183, 'Live retail AI capability suite', 'Approved AI features in production, integrated with POS, OMS, and inventory systems, accepted by merchandising and operations leads.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (183, 'Retail AI monitoring dashboard', 'Real-time view of model performance, revenue and inventory impact metrics, and alert thresholds set to your agreed commercial tolerances.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (183, 'Merchandising governance documentation', 'Written policies and in-system controls covering when merchandising teams must review or override AI pricing and replenishment recommendations.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (183, 'AI operations handover pack', 'Model cards, integration diagrams, monitoring runbooks, and retraining schedules for your technology and retail operations teams.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (183, 'Which AI features are typically activated in this deployment?', 'Those validated in the AI Design phase: commonly demand forecasting, personalised recommendations, and markdown optimisation. Scope is confirmed from your approved specifications.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (183, 'How do you protect pricing integrity during AI activation?', 'Shadow-mode testing runs pricing AI against live data without acting on outputs until accuracy thresholds are met. Merchandising override controls remain active after full launch.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (183, 'Who is responsible for retraining AI models over time?', 'Your technology team, using the retraining schedules and model documentation handed over at the end of the engagement. The DigitalQatalyst team can provide managed-service support if needed.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (183, 'How do we get started?', 'Provide your approved AI deployment specifications and the DigitalQatalyst team will confirm production environment requirements and the use-case activation sequence.', 3);

-- Retail Operations (High-Impact) - Managed (variant 184)
UPDATE product_content SET
  description = 'An ongoing managed service that runs and continuously improves your retail operations platform, with SLA-backed monitoring, monthly performance reporting across store and digital channels, and proactive optimisation by the DigitalQatalyst team.',
  positioning = 'Keep retail operations and omnichannel commerce performing reliably with continuous monitoring, proactive optimisation, and monthly commercial performance reporting.',
  hero_summary = 'An ongoing managed service that runs and continuously improves your retail operations platform, with SLA-backed monitoring, monthly performance reporting across store and digital channels, and proactive optimisation by the DigitalQatalyst team.',
  overview_paragraphs = '["The Retail Operations Managed Service service runs SLA-backed operations with continuous monitoring, optimisation, and lifecycle governance. This managed service provides SLA-backed operations and continuous improvement.","Run and improve retail operations and omnichannel commerce with ongoing monitoring, reporting, and optimisation so performance keeps pace with your business."]'::jsonb,
  audience_description = 'Built for retail, commerce & store operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This managed service covers ongoing operations, reporting, and improvement for retail operations - managed.","You receive predictable SLA-backed support aligned to agreed service levels."]'::jsonb,
  delivery_process = '{"totalDuration":"Ongoing","steps":[{"step":1,"title":"Onboard","duration":"Week 1","body":"We align on scope, SLAs, access, and how we will run the service with your team.","whatHappens":"Scope alignment, SLA setup, and access provisioning","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Operate","duration":"Ongoing","body":"We run agreed operations with monitoring, incident response, and SLA-backed reporting.","whatHappens":"Monitoring, incident response, and service reporting","dqEffort":"high","yourEffort":"low"},{"step":3,"title":"Improve","duration":"Ongoing","body":"We review performance, apply optimisations, and keep the service aligned as your needs change.","whatHappens":"Performance reviews, optimisations, and roadmap updates","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Omnichannel performance reporting covers store and digital in a single monthly view","Proactive optimisation included alongside reactive incident management","Named retail-sector team with commercial context, not a generic support function"]'::jsonb,
  why_it_matters = '{"hook":"Retail success depends on consistent store execution, inventory accuracy, and connected customer journeys.","problemParagraph":"Many organisations struggle to sustain performance across your retail operations after go-live, with reactive support, rising costs, and declining platform value. This managed service provides SLA-backed operations and continuous improvement.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive operations","description":"retail operations issues are addressed after impact, not prevented through proactive management."},{"title":"Declining performance","description":"Platform value erodes without continuous optimisation and lifecycle governance."},{"title":"Unpredictable support","description":"Service levels and escalation paths are unclear when teams need help most."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"SLA-backed operations","description":"Predictable service levels and structured incident management keep platforms running."},{"title":"Continuous optimisation","description":"Proactive monitoring and improvement sustain performance and user satisfaction."},{"title":"Lifecycle governance","description":"Regular reviews and reporting align platform evolution with business priorities."}]}}'::jsonb,
  faq_intro = 'Key questions about the Retail Operations managed service.'
WHERE variant_id = 184;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (184, 'Monthly omnichannel performance report', 'Conversion, fulfilment accuracy, inventory availability, and system-uptime metrics across all in-scope channels, delivered every month.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (184, 'Optimisation log', 'Record of every workflow adjustment, configuration change, and integration fix made during the service period, with before-and-after metrics noted.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (184, 'SLA compliance report', 'Monthly record of incidents, response times, and resolution times against agreed SLA targets, with root-cause notes for any breaches.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (184, 'Annual retail technology roadmap', 'Forward-looking plan identifying optimisation priorities, platform upgrade opportunities, and recommended investments for the next 12 months.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (184, 'What systems does the managed service cover?', 'POS, OMS, WMS, and the integrations connecting them across your in-scope channels. Additional platforms can be onboarded as your estate grows.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (184, 'What SLA response times apply?', 'Targets are agreed during onboarding based on platform criticality. Customer-facing system failures receive priority-one treatment.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (184, 'Does the managed service include peak-trading support?', 'Yes. The DigitalQatalyst team reviews your trading calendar during onboarding and confirms enhanced monitoring windows for peak periods.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (184, 'How do we get started?', 'Contact the DigitalQatalyst team to schedule a service onboarding call covering systems in scope, SLA targets, reporting format, and the named contacts on both sides.', 3);

-- Service Operations (High-Impact) - Assess (variant 185)
UPDATE product_content SET
  description = 'A structured assessment of your service, field, or professional operations that identifies the scheduling failures, delivery bottlenecks, and quality gaps reducing throughput and customer satisfaction, and returns a prioritised improvement roadmap.',
  positioning = 'Get a clear picture of where your service operations underperform, with every recommendation ranked by throughput impact and delivery effort.',
  hero_summary = 'A structured assessment of your service, field, or professional operations that identifies the scheduling failures, delivery bottlenecks, and quality gaps reducing throughput and customer satisfaction, and returns a prioritised improvement roadmap.',
  overview_paragraphs = '["The Service Operations Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps operational maturity and returns prioritised improvements your operations leaders can act on.","See how service operations perform today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for service operations & field service leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews service operations across business operations and productivity.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Covers scheduling, dispatch, delivery quality, and customer experience in one assessment","Throughput and retention impact scored on every recommendation","Fixed-scope with a prioritised roadmap ready within the week"]'::jsonb,
  why_it_matters = '{"hook":"Service businesses win on scheduling discipline, field execution, and customer communication.","problemParagraph":"Many service organisations coordinate field teams with manual scheduling, disconnected CRM data, and inconsistent job execution. This assessment maps operational maturity and returns prioritised improvements your operations leaders can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Fragmented operations data","description":"Service operations teams work from disconnected systems without a single operational view."},{"title":"Inconsistent field processes","description":"Standard operating procedures vary by site, team, or shift."},{"title":"Limited digitisation baseline","description":"Automation and analytics opportunities are unclear and unprioritised."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Operational priority map","description":"You know which service operations processes and systems to improve first."},{"title":"Ranked improvement backlog","description":"Gaps are ordered for design, technology, and investment."},{"title":"Leadership-ready roadmap","description":"Recommendations support governance review and transformation funding."}]}}'::jsonb,
  faq_intro = 'Key questions about the Service Operations assessment.'
WHERE variant_id = 185;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (185, 'Service throughput diagnostic', 'Data-backed analysis of job completion rates, rework volumes, and first-visit resolution rates, with root causes identified for the highest-cost failure patterns.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (185, 'Scheduling and dispatch efficiency report', 'Assessment of your scheduling model, dispatch logic, and field coverage with the specific inefficiencies costing you capacity and response time.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (185, 'Customer experience gap map', 'Stage-by-stage view of where service commitments are missed, with the customer-satisfaction and retention impact of each gap quantified.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (185, 'Prioritised improvement roadmap', 'Sequenced action plan ranked by throughput and retention impact, with ownership suggestions and a phasing recommendation for leadership.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (185, 'Which types of service operations does the assessment cover?', 'Field service, professional services delivery, maintenance and repair, technical support, and customer service operations. Scope is confirmed with the DigitalQatalyst team before start.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (185, 'What data do you need?', 'Job completion records, scheduling data, rework logs, and customer satisfaction scores. No customer PII is required beyond anonymised feedback data.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (185, 'Can the assessment cover remote and on-site service delivery?', 'Yes. The assessment maps both remote and field delivery models where your operation runs a combination of both.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (185, 'How do we get started?', 'Request a consultation and the DigitalQatalyst team will confirm the operational scope, data requirements, and assessment schedule.', 3);

-- Service Operations (High-Impact) - Design (variant 186)
UPDATE product_content SET
  description = 'A design engagement that turns your service operations improvement goals into job-scheduling blueprints, field workflow specifications, and technology integration plans your delivery teams can implement and go live with.',
  positioning = 'Design the service operations workflows your teams need: scheduling logic, field processes, and system integrations built for throughput and quality.',
  hero_summary = 'A design engagement that turns your service operations improvement goals into job-scheduling blueprints, field workflow specifications, and technology integration plans your delivery teams can implement and go live with.',
  overview_paragraphs = '["The Service Operations Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement defines service operations and build-ready specifications.","Turn service operations goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for service operations & field service leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate service operations requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Field and back-office workflow design completed together, not in separate engagements","Integration architecture built to your existing FSM, CRM, and ERP systems","Completion-standard specifications designed to measurably cut rework rates"]'::jsonb,
  why_it_matters = '{"hook":"Service businesses win on scheduling discipline, field execution, and customer communication.","problemParagraph":"Many service businesses digitise operations without designed dispatch workflows, job standards, or specifications field teams can adopt. This design engagement defines service operations and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined operational workflows","description":"Service operations journeys from intake to completion are not designed end to end."},{"title":"Integration gaps","description":"Field, ERP, and customer systems lack clear data and event contracts."},{"title":"Rollout ambiguity","description":"Teams lack specs to pilot and scale changes across sites."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Aligned operational designs","description":"Workflows reflect how service operations teams actually deliver service."},{"title":"Consistent standards","description":"Data, integration, and governance requirements are defined upfront."},{"title":"Implementation-ready specs","description":"Delivery teams receive artefacts they can execute across locations."}]}}'::jsonb,
  faq_intro = 'Key questions about the Service Operations design engagement.'
WHERE variant_id = 186;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (186, 'Job lifecycle workflow designs', 'End-to-end workflow specifications from job intake to closure, with quality checkpoints, escalation paths, and completion standards defined at each stage.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (186, 'Field service process specifications', 'Step-by-step field task definitions, completion-standard checklists, and sign-off requirements designed to reduce rework and improve first-visit resolution.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (186, 'Technology integration architecture', 'Data-flow diagrams connecting FSM, CRM, ERP, and mobile field-application data into a coherent operational picture for scheduling and reporting.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (186, 'Adoption and training plan', 'Role-specific onboarding materials for dispatch teams, field staff, and service managers, with a rollout sequence and go/no-go criteria.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (186, 'Does the design cover both back-office scheduling and field execution?', 'Yes. Job lifecycle designs span intake, scheduling, dispatch, field execution, and closure, with handoff specifications at each stage.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (186, 'What if we are replacing our FSM platform as part of this programme?', 'The integration architecture can be designed for your target FSM system if a platform migration is already planned. The DigitalQatalyst team confirms the approach during scoping.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (186, 'How are the specifications handed to the delivery team?', 'Annotated workflow diagrams, process specifications, and integration architectures in a shared workspace formatted for handover to internal or vendor delivery teams.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (186, 'How do we get started?', 'Book a scoping call and the DigitalQatalyst team will confirm the workflow scope, the workshops required, and the design sprint schedule.', 3);

-- Service Operations (High-Impact) - AI Design (variant 187)
UPDATE product_content SET
  description = 'A service-operations AI design engagement that validates which AI capabilities will improve scheduling accuracy, first-visit resolution, and service quality prediction, producing responsible workflow designs and build-ready specifications before any development commitment.',
  positioning = 'Design AI for service operations with validated scheduling and quality use cases, responsible guardrails, and deployment specifications ready before build.',
  hero_summary = 'A service-operations AI design engagement that validates which AI capabilities will improve scheduling accuracy, first-visit resolution, and service quality prediction, producing responsible workflow designs and build-ready specifications before any development commitment.',
  overview_paragraphs = '["The Service Operations AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for service operations, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for service operations & field service leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for service operations.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Use-case validation against your actual job and technician data, not generic industry benchmarks","Dispatcher override controls specified in every AI-assisted scheduling workflow","Deployment specifications ready for handover to your engineering or FSM vendor team"]'::jsonb,
  why_it_matters = '{"hook":"Service businesses win on scheduling discipline, field execution, and customer communication.","problemParagraph":"Many organisations apply AI to your field service operations without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for service operations lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for service operations are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Key questions about designing AI capabilities for service operations.'
WHERE variant_id = 187;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (187, 'Validated service AI use-case register', 'Candidate AI use cases scored against throughput value, data availability, and responsible-AI criteria specific to service and field operations.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (187, 'Responsible dispatch AI workflow designs', 'Step-by-step specifications for AI-assisted scheduling and dispatch, with dispatcher override controls, confidence thresholds, and escalation procedures.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (187, 'Service data readiness report', 'Assessment of job history, technician, asset, and customer data required for each approved AI use case, with gaps and remediation steps.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (187, 'AI deployment specification', 'Build-ready documentation covering model selection, FSM integration points, monitoring metrics, and rollback procedures for each approved service AI use case.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (187, 'Which AI use cases make sense for service operations?', 'Predictive scheduling optimisation, first-visit-resolution modelling, asset failure prediction, and service quality forecasting are common starting points. The DigitalQatalyst team validates feasibility against your data.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (187, 'How much historical job data is needed?', 'Typically two or more years of job records with technician, asset, and outcome data. The data readiness report specifies exactly what each use case requires.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (187, 'How do you design AI scheduling without removing human dispatcher judgement?', 'Override controls and confidence thresholds are built into every dispatch AI workflow design. The specification defines exactly when and how dispatchers retain authority over final scheduling decisions.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (187, 'How do we get started?', 'Request a scoping call and the DigitalQatalyst team will confirm which AI use cases to evaluate and what data access is needed for the feasibility assessment.', 3);

-- Service Operations (High-Impact) - Deploy (variant 188)
UPDATE product_content SET
  description = 'A managed service operations deployment that configures, integrates, tests, and launches your field service management and scheduling platform capabilities, with structured quality assurance and a formal handover to your service operations team.',
  positioning = 'Go live with improved service operations tools through a tested, managed build that covers scheduling, dispatch, field workflows, and operations handover.',
  hero_summary = 'A managed service operations deployment that configures, integrates, tests, and launches your field service management and scheduling platform capabilities, with structured quality assurance and a formal handover to your service operations team.',
  overview_paragraphs = '["The Service Operations Deploy service delivers configured, tested capabilities with structured integration, quality assurance, and handover to your operations team. This implementation delivers configured, tested capabilities with structured handover.","Implement agreed service operations changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
  audience_description = 'Built for service operations & field service leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement delivers configured, tested, and validated service operations assets aligned to approved scope.","Each output supports go-live readiness and structured handover to your operations team."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Job-type-specific acceptance testing with formal sign-off before any live service traffic","Field mobile application and back-office scheduling tested together before go-live","Hypercare support covers the first weeks of live service operation"]'::jsonb,
  why_it_matters = '{"hook":"Service businesses win on scheduling discipline, field execution, and customer communication.","problemParagraph":"Many organisations stall between approved designs and production for your field service operations, with integration gaps, quality risks, and delayed go-live. This implementation delivers configured, tested capabilities with structured handover.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Stalled implementation","description":"Approved designs for service operations sit idle while teams struggle to coordinate build and integration."},{"title":"Quality and integration risk","description":"Testing gaps and platform dependencies threaten go-live timelines and stability."},{"title":"Unclear handover","description":"Operations teams lack the documentation and knowledge transfer needed to run live systems."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Production-ready delivery","description":"Capabilities are built, tested, and validated against agreed acceptance criteria."},{"title":"Integrated platforms","description":"Solutions are deployed with security, governance, and platform requirements met."},{"title":"Confident go-live","description":"Structured handover equips your teams to operate and evolve the capability."}]}}'::jsonb,
  faq_intro = 'Key questions about the Service Operations deployment engagement.'
WHERE variant_id = 188;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (188, 'Configured service operations platform', 'FSM, scheduling, and mobile field applications configured and integrated across your in-scope job types and regions, with data flows tested end-to-end.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (188, 'Test results and sign-off report', 'Test evidence covering integration, job lifecycle, and acceptance scenarios for each job type, with all critical issues resolved before go-live.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (188, 'Staff training completion record', 'Documented training completion for dispatch teams, field staff, and service managers, with competency assessed against the operational standards in your workflow designs.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (188, 'Service operations handover pack', 'System configuration documentation, runbooks, escalation contacts, and first-90-days operational guidance for your service management team.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (188, 'Can we deploy one job type or region first before expanding?', 'Yes. The deployment plan typically phases launch by job type or region, allowing validation at smaller scale before full rollout.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (188, 'How is existing job and asset data migrated?', 'Migration is planned, validated, and tested in a non-production environment before go-live. The migration plan is confirmed with your operations team during the first three weeks.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (188, 'What if acceptance testing reveals issues with field mobile workflows?', 'Issues are logged, triaged, and resolved before that job type proceeds to launch. Field and back-office sign-offs are separate gates so a field issue does not delay scheduling changes.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (188, 'How do we get started?', 'Share your approved workflow specifications with the DigitalQatalyst team and we will scope the deployment plan and environment requirements.', 3);

