  package_highlights = '["Discipline-by-discipline acceptance testing with formal sign-off before any live client interactions","EHR and PMS workflows tested together before go-live to prevent care-record gaps at launch","Hypercare monitoring covers the first weeks of live wellness operation"]'::jsonb,
  why_it_matters = '{"hook":"Wellness providers depend on seamless booking, care coordination, and compliant client management.","problemParagraph":"Many organisations stall between approved designs and production for your wellness operations, with integration gaps, quality risks, and delayed go-live. This implementation delivers configured, tested capabilities with structured handover.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Stalled implementation","description":"Approved designs for wellness operations sit idle while teams struggle to coordinate build and integration."},{"title":"Quality and integration risk","description":"Testing gaps and platform dependencies threaten go-live timelines and stability."},{"title":"Unclear handover","description":"Operations teams lack the documentation and knowledge transfer needed to run live systems."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Production-ready delivery","description":"Capabilities are built, tested, and validated against agreed acceptance criteria."},{"title":"Integrated platforms","description":"Solutions are deployed with security, governance, and platform requirements met."},{"title":"Confident go-live","description":"Structured handover equips your teams to operate and evolve the capability."}]}}'::jsonb,
  faq_intro = 'Key questions about the Wellness Operations deployment engagement.'
WHERE variant_id = 200;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (200, 'Configured wellness operations platform', 'Practice management system and EHR configured and integrated across your in-scope service types and sites, with booking, care record, and billing flows tested end-to-end.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (200, 'Test results and discipline sign-off report', 'Test evidence covering integration, care workflow, and acceptance scenarios for each discipline, with all critical issues resolved before any live client access.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (200, 'Staff training completion record', 'Documented training completion for reception, practitioners, and clinic managers, with competency assessed against the client experience and workflow standards in your design.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (200, 'Wellness operations handover pack', 'Platform configuration documentation, care-workflow runbooks, escalation contacts, and first-90-days operational guidance for your clinic management team.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (200, 'Can we go live with one clinic site or discipline before expanding?', 'Yes. The deployment plan typically phases activation by site or discipline, allowing validation at smaller scale before full rollout.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (200, 'How is existing client data migrated?', 'Client data migration is planned, validated, and tested in a non-production environment before go-live. The migration approach is confirmed with your operations and clinical leads during the first three weeks.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (200, 'What if acceptance testing reveals issues with a specific discipline workflow?', 'Issues are logged, triaged, and resolved before that discipline proceeds to launch. Discipline-specific sign-off gates mean a delay in one area does not hold back others that are ready.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (200, 'How do we get started?', 'Share your approved workflow specifications with the DigitalQatalyst team and we will scope the deployment plan and environment requirements.', 3);

