  deliverables_summary = '["This managed service covers ongoing operations, reporting, and improvement for wellness operations - managed.","You receive predictable SLA-backed support aligned to agreed service levels."]'::jsonb,
  delivery_process = '{"totalDuration":"Ongoing","steps":[{"step":1,"title":"Onboard","duration":"Week 1","body":"We align on scope, SLAs, access, and how we will run the service with your team.","whatHappens":"Scope alignment, SLA setup, and access provisioning","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Operate","duration":"Ongoing","body":"We run agreed operations with monitoring, incident response, and SLA-backed reporting.","whatHappens":"Monitoring, incident response, and service reporting","dqEffort":"high","yourEffort":"low"},{"step":3,"title":"Improve","duration":"Ongoing","body":"We review performance, apply optimisations, and keep the service aligned as your needs change.","whatHappens":"Performance reviews, optimisations, and roadmap updates","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Scheduling and client retention reported together in a single monthly view","Proactive scheduling optimisation included alongside reactive incident management","Named team with wellness-sector and clinical operations context, not a generic IT support function"]'::jsonb,
  why_it_matters = '{"hook":"Wellness providers depend on seamless booking, care coordination, and compliant client management.","problemParagraph":"Many organisations struggle to sustain performance across your wellness operations after go-live, with reactive support, rising costs, and declining platform value. This managed service provides SLA-backed operations and continuous improvement.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive operations","description":"wellness operations issues are addressed after impact, not prevented through proactive management."},{"title":"Declining performance","description":"Platform value erodes without continuous optimisation and lifecycle governance."},{"title":"Unpredictable support","description":"Service levels and escalation paths are unclear when teams need help most."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"SLA-backed operations","description":"Predictable service levels and structured incident management keep platforms running."},{"title":"Continuous optimisation","description":"Proactive monitoring and improvement sustain performance and user satisfaction."},{"title":"Lifecycle governance","description":"Regular reviews and reporting align platform evolution with business priorities."}]}}'::jsonb,
  faq_intro = 'Key questions about the Wellness Operations managed service.'
WHERE variant_id = 202;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (202, 'Monthly wellness operations performance report', 'Appointment fill rates, client retention, care coordination quality metrics, and system-availability data across all in-scope platforms, delivered every month.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (202, 'Optimisation log', 'Record of every scheduling adjustment, workflow change, and platform integration fix made during the service period, with before-and-after performance metrics.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (202, 'SLA compliance report', 'Monthly record of incidents, response times, and resolution times against agreed SLA targets, with root-cause notes for any platform availability breaches.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (202, 'Annual wellness operations roadmap', 'Forward-looking plan identifying scheduling optimisation priorities, platform upgrade opportunities, and recommended investments for the next 12 months of your practice.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (202, 'What platforms does the managed service cover?', 'Your practice management system, EHR, and client-communication platforms, plus the integrations connecting them. Additional systems can be onboarded as your estate grows.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (202, 'What SLA response times apply to booking-critical incidents?', 'Response and resolution targets are agreed during onboarding. Incidents affecting live client booking and care record access receive priority-one treatment.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (202, 'Does the service include peak-demand support for busy clinic periods?', 'Yes. The DigitalQatalyst team reviews your appointment calendar during onboarding and confirms enhanced monitoring for high-demand periods.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (202, 'How do we get started?', 'Contact the DigitalQatalyst team to schedule a service onboarding call covering platforms in scope, SLA targets, reporting format, and named contacts on both sides.', 3);
